import { describe, it, expect, vi, beforeEach } from 'vitest'

vi.mock('./deleteService', () => ({
  deleteItem: vi.fn()
}))
import { deleteItem } from './deleteService'

import { handleDelete } from './handler'

describe('handleDelete', () => {
  let event: any

  beforeEach(() => {
    event = {
      preventDefault: vi.fn(),
      target: { dataset: { id: '123' } }
    }
    vi.clearAllMocks()
  })

  it('should handle happy path', () => {
    handleDelete(event)
    expect(event.preventDefault).toHaveBeenCalled()
    expect(deleteItem).toHaveBeenCalledWith('123')
  })

  it('should handle edge case when target has no dataset id', () => {
    event.target.dataset.id = undefined
    handleDelete(event)
    expect(event.preventDefault).toHaveBeenCalled()
    expect(deleteItem).not.toHaveBeenCalled()
  })

  it('should handle null/empty arguments', () => {
    const nullEvent = null as any
    const undefinedEvent = undefined as any
    const zeroEvent = 0 as any

    expect(() => handleDelete(nullEvent)).not.toThrow()
    expect(() => handleDelete(undefinedEvent)).not.toThrow()
    expect(() => handleDelete(zeroEvent)).not.toThrow()
  })
})